#include <bits/stdc++.h>
using namespace std;
using ll=long long;
using ld=long double;
using P=pair<ll,ll>;
using V=vector<ll>;
#define rep(i,n) for(int i=0;i<n;i++)
#define REP(i,n) for(int i=1;i<=n;i++)

vector<string> a(9);
vector<int> dx={-1,0,1,0},dy={0,1,0,-1};
int px=8,py=4;
int mx=0,my=4;

bool partner(){
    int task;
    cin >> task;
    if(task==0){
        int d;
        cin >> d;
        px+=dx[d];
        py+=dy[d];
        a[px][py]='.';
    }
    if(task==1||task==2){
        int x,y;
        cin >> x >> y;
    }
    if(task==3) return true;
    return false;

}

int dis(int ax,int ay,int bx,int by){
    return abs(ax-bx)+abs(ay-by);
}

int main(){
    string firsec;
    cin >> firsec;
    rep(i,9) cin >> a[i];
    if(firsec=="Second") if(partner()) return 0;
    else swap(px,mx);

    while(true){
        ld u=0,d=0,l=0,r=0;
        rep(i,9) rep(j,9){
            if(dis(i,j,mx,my)<dis(i,j,px,py)&&a[i][j]=='#'){
                if(i<=mx&&abs(j-my)<=mx-i) u+=1;
                if(i>=mx&&abs(j-my)<=i-mx) d+=1;
                if(j<=my&&abs(i-mx)<=my-j) l+=1;
                if(j>=my&&abs(i-mx)<=j-my) r+=1;
            }
        }
        int c=0,cc=0;
        rep(l,4){
            int nx=mx+dx[l],ny=my+dy[l];
            if(0<=nx&&nx<9&&0<=ny&&ny<9){
                c++;
                if(a[nx][ny]=='#') cc++;
            }
        }
        vector<int> v={1,1,1,1};
        if(c!=d){
            rep(l,4){
                int nx=mx+dx[l],ny=my+dy[l];
                if(0<=nx&&nx<9&&0<=ny&&ny<9){
                    if(a[nx][ny]=='.') v[l]=0;
                }
            }
        }

        u*=v[0];
        r*=v[1];
        d*=v[2];
        l*=v[3];

        if(u>=r&&u>=d&&u>=l) cout << "0 0" << endl;
        else if(r>=u&&r>=d&&r>=l) cout << "0 1" << endl;
        else if(d>=u&&d>=r&&d>=l) cout << "0 2" << endl;
        else cout << "0 3" << endl;

        if(partner()) return 0;

    }
}
